function validateSql(params) {
  const { sql, allowedOperations } = params;
  const upperSql = sql.toUpperCase().trim();
  const forbidden = ['INSERT', 'UPDATE', 'DELETE', 'DROP', 'ALTER', 'TRUNCATE', 'CREATE', 'GRANT', 'REVOKE'];
  for (const keyword of forbidden) {
    if (upperSql.startsWith(keyword)) {
      return { valid: false, error: `禁止执行 ${keyword} 操作` };
    }
  }
  if (!upperSql.includes('LIMIT')) {
    return { valid: true, sql: sql + ' LIMIT 10000', warning: '已自动添加 LIMIT 10000' };
  }
  return { valid: true, sql: sql };
}

function analyzeData(params) {
  const { queryResult } = params;
  const rows = queryResult.rows || [];
  const columns = queryResult.columns || [];
  const rowCount = rows.length;
  const colCount = columns.length;
  const hasTimeColumn = columns.some(c => ['date', 'time', 'month', 'year', 'day', 'week', 'created_at', 'updated_at'].some(t => c.name.toLowerCase().includes(t)));
  const hasNumericColumn = columns.some(c => ['int', 'float', 'decimal', 'numeric', 'bigint', 'double'].some(t => c.type.toLowerCase().includes(t)));
  const hasCategoryColumn = columns.some(c => ['varchar', 'text', 'char'].some(t => c.type.toLowerCase().includes(t)));
  let suggestedChartType = 'table';
  if (rowCount <= 1) suggestedChartType = 'metric';
  else if (hasTimeColumn && hasNumericColumn) suggestedChartType = 'line';
  else if (hasCategoryColumn && hasNumericColumn && rowCount <= 10) suggestedChartType = 'pie';
  else if (hasCategoryColumn && hasNumericColumn) suggestedChartType = 'bar';
  return { rowCount, colCount, hasTimeColumn, hasNumericColumn, hasCategoryColumn, suggestedChartType };
}

