async function runAnomalyChecks(params) {
  const { anomalyRules, db } = params;
  const results = [];
  for (const rule of anomalyRules) {
    const queryResult = await db.query(rule.sql);
    const value = queryResult.rows[0]?.[rule.valueColumn];
    const isAnomaly = rule.operator === 'gt' ? value > rule.threshold : rule.operator === 'lt' ? value < rule.threshold : value !== rule.threshold;
    if (isAnomaly) {
      results.push({ ruleName: rule.name, severity: rule.severity, currentValue: value, threshold: rule.threshold, description: rule.description });
    }
  }
  return { anomalies: results, checkTime: new Date().toISOString(), totalRules: anomalyRules.length };
}

